import 'package:flutter/material.dart';\nimport 'package:flutter_riverpod/flutter_riverpod.dart';\nimport '../../data/models/workflow.dart';\nimport '../../services/workflow_service.dart';\nimport '../../data/auth/auth_provider.dart';\nimport 'task_detail_page.dart';\n\nclass AvailableTasksPage extends ConsumerStatefulWidget {\n  final List<WorkflowTask> tasks;\n\n  const AvailableTasksPage({super.key, required this.tasks});\n\n  @override\n  ConsumerState<AvailableTasksPage> createState() => _AvailableTasksPageState();\n}\n\nclass _AvailableTasksPageState extends ConsumerState<AvailableTasksPage> {\n  final WorkflowService workflowService = WorkflowService();\n  List<WorkflowTask> _filteredTasks = [];\n  String _selectedStage = 'All';\n  String _selectedPriority = 'All';\n  bool _isLoading = false;\n\n  @override\n  void initState() {\n    super.initState();\n    filteredTasks = List.from(widget.tasks);\n    sortTasksByPriority();\n  }\n\n  void sortTasksByPriority() {\n    filteredTasks.sort((a, b) {\n      // Sort by priority (high to low), then by creation date (newest first)\n      if (a.priority != b.priority) {\n        return b.priority.compareTo(a.priority);\n      }\n      return b.createdAt.compareTo(a.createdAt);\n    });\n  }\n\n  void _applyFilters() {\n    setState(() {\n      _filteredTasks = widget.tasks.where((task) {\n        bool stageMatch = _selectedStage == 'All' || task.stageName == _selectedStage;\n        bool priorityMatch = _selectedPriority == 'All' || \n            (_selectedPriority == 'High' && task.priority > 3) ||\n            (_selectedPriority == 'Normal' && task.priority <= 3);\n        return stageMatch && priorityMatch;\n      }).toList();\n      _sortTasksByPriority();\n    });\n  }\n\n  Future<void> _refreshTasks() async {\n    final user = ref.read(authProvider);\n    if (user != null) {\n      setState(() => _isLoading = true);\n      try {\n        final newTasks = await _workflowService.getAvailableTasks(user.uid);\n        setState(() {\n          widget.tasks.clear();\n          widget.tasks.addAll(newTasks);\n          _applyFilters();\n          _isLoading = false;\n        });\n      } catch (e) {\n        setState(() => _isLoading = false);\n        _showErrorSnackBar('Failed to refresh tasks: $e');\n      }\n    }\n  }\n\n  @override\n  Widget build(BuildContext context) {\n    final uniqueStages = ['All', ...widget.tasks.map((t) => t.stageName).toSet()];\n    \n    return Scaffold(\n      appBar: AppBar(\n        title: const Text('Available Tasks'),\n        backgroundColor: Colors.deepOrange,\n        foregroundColor: Colors.white,\n        actions: [\n          IconButton(\n            icon: const Icon(Icons.filter_list),\n            onPressed: _showFilterDialog,\n          ),\n          IconButton(\n            icon: const Icon(Icons.refresh),\n            onPressed: _refreshTasks,\n          ),\n        ],\n      ),\n      body: Column(\n        children: [\n          _buildFilterChips(),\n          Expanded(\n            child: _isLoading\n                ? const Center(child: CircularProgressIndicator())\n                : RefreshIndicator(\n                    onRefresh: _refreshTasks,\n                    child: _filteredTasks.isEmpty\n                        ? _buildEmptyState()\n                        : ListView.builder(\n                            padding: const EdgeInsets.all(16),\n                            itemCount: _filteredTasks.length,\n                            itemBuilder: (context, index) {\n                              return _buildTaskCard(_filteredTasks[index]);\n                            },\n                          ),\n                  ),\n          ),\n        ],\n      ),\n    );\n  }\n\n  Widget _buildFilterChips() {\n    return Container(\n      padding: const EdgeInsets.all(16),\n      child: Column(\n        crossAxisAlignment: CrossAxisAlignment.start,\n        children: [\n          Row(\n            children: [\n              const Icon(Icons.filter_list, size: 20),\n              const SizedBox(width: 8),\n              Text(\n                'Filters: ${_filteredTasks.length} tasks',\n                style: const TextStyle(fontWeight: FontWeight.w600),\n              ),\n            ],\n          ),\n          const SizedBox(height: 8),\n          SingleChildScrollView(\n            scrollDirection: Axis.horizontal,\n            child: Row(\n              children: [\n                _buildFilterChip(\n                  'Stage: $_selectedStage',\n                  _selectedStage != 'All',\n                  () => _showStageFilter(),\n                ),\n                const SizedBox(width: 8),\n                _buildFilterChip(\n                  'Priority: $_selectedPriority',\n                  _selectedPriority != 'All',\n                  () => _showPriorityFilter(),\n                ),\n                const SizedBox(width: 8),\n                if (_selectedStage != 'All' || _selectedPriority != 'All')\n                  _buildFilterChip(\n                    'Clear All',\n                    false,\n                    _clearFilters,\n                    isAction: true,\n                  ),\n              ],\n            ),\n          ),\n        ],\n      ),\n    );\n  }\n\n  Widget _buildFilterChip(String label, bool isActive, VoidCallback onTap, {bool isAction = false}) {\n    return GestureDetector(\n      onTap: onTap,\n      child: Container(\n        padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 6),\n        decoration: BoxDecoration(\n          color: isActive ? Colors.deepOrange : (isAction ? Colors.grey[300] : Colors.grey[100]),\n          borderRadius: BorderRadius.circular(20),\n          border: Border.all(\n            color: isActive ? Colors.deepOrange : Colors.grey[400]!,\n          ),\n        ),\n        child: Text(\n          label,\n          style: TextStyle(\n            color: isActive ? Colors.white : Colors.black87,\n            fontWeight: isActive ? FontWeight.w600 : FontWeight.normal,\n            fontSize: 12,\n          ),\n        ),\n      ),\n    );\n  }\n\n  Widget _buildEmptyState() {\n    return Center(\n      child: Column(\n        mainAxisAlignment: MainAxisAlignment.center,\n        children: [\n          Icon(\n            Icons.inbox_outlined,\n            size: 64,\n            color: Colors.grey[400],\n          ),\n          const SizedBox(height: 16),\n          Text(\n            'No available tasks',\n            style: TextStyle(\n              fontSize: 18,\n              color: Colors.grey[600],\n              fontWeight: FontWeight.w500,\n            ),\n          ),\n          const SizedBox(height: 8),\n          Text(\n            'Check back later for new tasks',\n            style: TextStyle(\n              color: Colors.grey[500],\n            ),\n          ),\n          const SizedBox(height: 24),\n          ElevatedButton(\n            onPressed: _refreshTasks,\n            child: const Text('Refresh'),\n          ),\n        ],\n      ),\n    );\n  }\n\n  Widget _buildTaskCard(WorkflowTask task) {\n    return Card(\n      margin: const EdgeInsets.only(bottom: 12),\n      elevation: 2,\n      child: InkWell(\n        onTap: () => _navigateToTaskDetail(task),\n        borderRadius: BorderRadius.circular(8),\n        child: Padding(\n          padding: const EdgeInsets.all(16),\n          child: Column(\n            crossAxisAlignment: CrossAxisAlignment.start,\n            children: [\n              Row(\n                children: [\n                  CircleAvatar(\n                    backgroundColor: _getStatusColor(task.status),\n                    child: Text(\n                      task.stageIcon,\n                      style: const TextStyle(fontSize: 16),\n                    ),\n                  ),\n                  const SizedBox(width: 12),\n                  Expanded(\n                    child: Column(\n                      crossAxisAlignment: CrossAxisAlignment.start,\n                      children: [\n                        Text(\n                          task.stageName,\n                          style: const TextStyle(\n                            fontSize: 16,\n                            fontWeight: FontWeight.bold,\n                          ),\n                        ),\n                        Text(\n                          'Order #${task.orderId}',\n                          style: TextStyle(\n                            color: Colors.grey[600],\n                            fontSize: 14,\n                          ),\n                        ),\n                      ],\n                    ),\n                  ),\n                  if (task.priority > 3)\n                    Container(\n                      padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 4),\n                      decoration: BoxDecoration(\n                        color: Colors.red.withOpacity(0.1),\n                        borderRadius: BorderRadius.circular(12),\n                        border: Border.all(color: Colors.red),\n                      ),\n                      child: Row(\n                        mainAxisSize: MainAxisSize.min,\n                        children: [\n                          const Icon(Icons.priority_high, size: 12, color: Colors.red),\n                          const SizedBox(width: 2),\n                          Text(\n                            'HIGH',\n                            style: TextStyle(\n                              color: Colors.red[700],\n                              fontSize: 10,\n                              fontWeight: FontWeight.bold,\n                            ),\n                          ),\n                        ],\n                      ),\n                    ),\n                ],\n              ),\n              const SizedBox(height: 12),\n              _buildTaskInfo(task),\n              const SizedBox(height: 12),\n              Row(\n                mainAxisAlignment: MainAxisAlignment.spaceBetween,\n                children: [\n                  Text(\n                    'Created: ${_formatDate(task.createdAt)}',\n                    style: TextStyle(\n                      color: Colors.grey[600],\n                      fontSize: 12,\n                    ),\n                  ),\n                  ElevatedButton(\n                    onPressed: () => _acceptTask(task),\n                    style: ElevatedButton.styleFrom(\n                      backgroundColor: Colors.green,\n                      foregroundColor: Colors.white,\n                      padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 8),\n                    ),\n                    child: const Text(\n                      'Accept',\n                      style: TextStyle(fontSize: 12),\n                    ),\n                  ),\n                ],\n              ),\n            ],\n          ),\n        ),\n      ),\n    );\n  }\n\n  Widget _buildTaskInfo(WorkflowTask task) {\n    return Column(\n      crossAxisAlignment: CrossAxisAlignment.start,\n      children: [\n        _buildInfoRow(\n          Icons.person,\n          'Customer',\n          task.orderDetails['customerName'] ?? 'Unknown',\n        ),\n        const SizedBox(height: 4),\n        _buildInfoRow(\n          Icons.shopping_bag,\n          'Garment',\n          task.orderDetails['garmentType'] ?? 'N/A',\n        ),\n        const SizedBox(height: 4),\n        _buildInfoRow(\n          Icons.currency_rupee,\n          'Amount',\n          '₹${task.orderDetails['totalAmount'] ?? 0}',\n        ),\n        const SizedBox(height: 4),\n        _buildInfoRow(\n          Icons.schedule,\n          'Delivery',\n          _formatDate(task.orderDetails['deliveryDate']),\n        ),\n      ],\n    );\n  }\n\n  Widget _buildInfoRow(IconData icon, String label, String value) {\n    return Row(\n      children: [\n        Icon(icon, size: 16, color: Colors.grey[600]),\n        const SizedBox(width: 8),\n        Text(\n          '$label: ',\n          style: TextStyle(\n            color: Colors.grey[600],\n            fontSize: 13,\n            fontWeight: FontWeight.w500,\n          ),\n        ),\n        Expanded(\n          child: Text(\n            value,\n            style: const TextStyle(\n              fontSize: 13,\n              fontWeight: FontWeight.w600,\n            ),\n          ),\n        ),\n      ],\n    );\n  }\n\n  void _showFilterDialog() {\n    showDialog(\n      context: context,\n      builder: (context) => AlertDialog(\n        title: const Text('Filter Tasks'),\n        content: Column(\n          mainAxisSize: MainAxisSize.min,\n          children: [\n            ListTile(\n              title: const Text('By Stage'),\n              trailing: const Icon(Icons.arrow_forward_ios),\n              onTap: () {\n                Navigator.pop(context);\n                _showStageFilter();\n              },\n            ),\n            ListTile(\n              title: const Text('By Priority'),\n              trailing: const Icon(Icons.arrow_forward_ios),\n              onTap: () {\n                Navigator.pop(context);\n                _showPriorityFilter();\n              },\n            ),\n            if (_selectedStage != 'All' || _selectedPriority != 'All')\n              ListTile(\n                title: const Text('Clear All Filters'),\n                trailing: const Icon(Icons.clear),\n                onTap: () {\n                  Navigator.pop(context);\n                  _clearFilters();\n                },\n              ),\n          ],\n        ),\n        actions: [\n          TextButton(\n            onPressed: () => Navigator.pop(context),\n            child: const Text('Close'),\n          ),\n        ],\n      ),\n    );\n  }\n\n  void _showStageFilter() {\n    final uniqueStages = ['All', ...widget.tasks.map((t) => t.stageName).toSet()];\n    \n    showDialog(\n      context: context,\n      builder: (context) => AlertDialog(\n        title: const Text('Filter by Stage'),\n        content: Column(\n          mainAxisSize: MainAxisSize.min,\n          children: uniqueStages.map((stage) => RadioListTile<String>(\n            title: Text(stage),\n            value: stage,\n            groupValue: _selectedStage,\n            onChanged: (value) {\n              setState(() {\n                _selectedStage = value!;\n              });\n              Navigator.pop(context);\n              _applyFilters();\n            },\n          )).toList(),\n        ),\n      ),\n    );\n  }\n\n  void _showPriorityFilter() {\n    showDialog(\n      context: context,\n      builder: (context) => AlertDialog(\n        title: const Text('Filter by Priority'),\n        content: Column(\n          mainAxisSize: MainAxisSize.min,\n          children: [\n            RadioListTile<String>(\n              title: const Text('All'),\n              value: 'All',\n              groupValue: _selectedPriority,\n              onChanged: (value) {\n                setState(() {\n                  _selectedPriority = value!;\n                });\n                Navigator.pop(context);\n                _applyFilters();\n              },\n            ),\n            RadioListTile<String>(\n              title: const Text('High Priority'),\n              value: 'High',\n              groupValue: _selectedPriority,\n              onChanged: (value) {\n                setState(() {\n                  _selectedPriority = value!;\n                });\n                Navigator.pop(context);\n                _applyFilters();\n              },\n            ),\n            RadioListTile<String>(\n              title: const Text('Normal Priority'),\n              value: 'Normal',\n              groupValue: _selectedPriority,\n              onChanged: (value) {\n                setState(() {\n                  _selectedPriority = value!;\n                });\n                Navigator.pop(context);\n                _applyFilters();\n              },\n            ),\n          ],\n        ),\n      ),\n    );\n  }\n\n  void _clearFilters() {\n    setState(() {\n      _selectedStage = 'All';\n      _selectedPriority = 'All';\n    });\n    _applyFilters();\n  }\n\n  void _navigateToTaskDetail(WorkflowTask task) {\n    Navigator.push(\n      context,\n      MaterialPageRoute(\n        builder: (context) => TaskDetailPage(\n          task: task,\n          isMyTask: false,\n          onTaskUpdated: _refreshTasks,\n        ),\n      ),\n    );\n  }\n\n  Future<void> _acceptTask(WorkflowTask task) async {\n    final user = ref.read(authProvider);\n    if (user != null) {\n      final success = await _workflowService.acceptTask(task.id, user.uid);\n      if (success) {\n        _showSuccessSnackBar('Task accepted successfully');\n        _refreshTasks();\n      } else {\n        _showErrorSnackBar('Failed to accept task');\n      }\n    }\n  }\n\n  Color _getStatusColor(String status) {\n    switch (status) {\n      case TaskStatus.pending:\n        return Colors.grey;\n      case TaskStatus.assigned:\n        return Colors.blue;\n      case TaskStatus.started:\n      case TaskStatus.resumed:\n        return Colors.green;\n      case TaskStatus.paused:\n        return Colors.orange;\n      case TaskStatus.completed:\n        return Colors.purple;\n      default:\n        return Colors.grey;\n    }\n  }\n\n  String _formatDate(dynamic date) {\n    if (date == null) return 'N/A';\n    try {\n      final DateTime dateTime = date is String ? DateTime.parse(date) : date;\n      return '${dateTime.day}/${dateTime.month}/${dateTime.year}';\n    } catch (e) {\n      return 'Invalid date';\n    }\n  }\n\n  void _showSuccessSnackBar(String message) {\n    ScaffoldMessenger.of(context).showSnackBar(\n      SnackBar(\n        content: Text(message),\n        backgroundColor: Colors.green,\n        behavior: SnackBarBehavior.floating,\n      ),\n    );\n  }\n\n  void _showErrorSnackBar(String message) {\n    ScaffoldMessenger.of(context).showSnackBar(\n      SnackBar(\n        content: Text(message),\n        backgroundColor: Colors.red,\n        behavior: SnackBarBehavior.floating,\n      ),\n    );\n  }\n}